const express = require('express');
const cors = require('cors');
const multer = require('multer');
const path = require('path');
require('dotenv').config();

const app = express();
const upload = multer({ 
    storage: multer.memoryStorage(),
    limits: { fileSize: 10 * 1024 * 1024 } // 10MB limit
});

// Enable CORS
app.use(cors());
app.use(express.json());

const PORT = process.env.PORT || 3000;
const FAL_API_KEY = process.env.FAL_API_KEY;
const APP_PASSWORD = process.env.APP_PASSWORD || 'MySecret3D2025';

if (!FAL_API_KEY) {
    console.error('⚠️  FAL_API_KEY environment variable is not set!');
}

console.log('🔐 Password protection:', APP_PASSWORD ? 'ENABLED' : 'DISABLED');

// Password middleware
const requirePassword = (req, res, next) => {
    const providedPassword = req.headers['x-app-password'];
    if (!providedPassword) {
        return res.status(401).json({ error: 'Password required', message: 'Please enter password to access this service' });
    }
    if (providedPassword !== APP_PASSWORD) {
        return res.status(403).json({ error: 'Incorrect password', message: 'The password you entered is incorrect' });
    }
    next();
};

// Health check
app.get('/api/health', (req, res) => {
    res.json({ status: 'ok', message: 'My3DConverter API is running!', hasApiKey: !!FAL_API_KEY, passwordProtection: true });
});

// Submit image to Meshy-6
app.post('/api/generate', requirePassword, upload.single('image'), async (req, res) => {
    try {
        if (!FAL_API_KEY) return res.status(500).json({ error: 'Server configuration error: API key not set' });
        if (!req.file) return res.status(400).json({ error: 'No image provided' });

        console.log('📸 Received image:', req.file.originalname, `(${(req.file.size / 1024).toFixed(2)} KB)`);
        const base64Image = req.file.buffer.toString('base64');
        const imageUrl = `data:${req.file.mimetype};base64,${base64Image}`;

        console.log('🚀 Submitting to Meshy-6...');
        const submitRes = await fetch('https://queue.fal.run/fal-ai/meshy/v6/image-to-3d', {
            method: 'POST',
            headers: { 'Authorization': `Key ${FAL_API_KEY}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ image_url: imageUrl, topology: 'triangle', target_polycount: 30000, symmetry_mode: 'auto', should_remesh: true, should_texture: true, enable_pbr: true, enable_safety_checker: true }),
        });

        if (!submitRes.ok) {
            const errText = await submitRes.text();
            return res.status(submitRes.status).json({ error: `Failed to submit: ${submitRes.statusText}`, details: errText });
        }

        const submitData = await submitRes.json();
        console.log('✅ Job submitted! ID:', submitData.request_id);
        res.json({ success: true, requestId: submitData.request_id, message: 'Job submitted successfully' });

    } catch (error) {
        console.error('❌ Error:', error);
        res.status(500).json({ error: error.message });
    }
});

// Check job status
app.get('/api/status/:requestId', requirePassword, async (req, res) => {
    try {
        if (!FAL_API_KEY) return res.status(500).json({ error: 'API key not configured' });
        const { requestId } = req.params;
        const statusRes = await fetch(`https://queue.fal.run/fal-ai/meshy/requests/${requestId}/status`, {
            headers: { 'Authorization': `Key ${FAL_API_KEY}` }
        });
        if (!statusRes.ok) return res.status(statusRes.status).json({ error: `Status check failed: ${statusRes.statusText}` });
        res.json(await statusRes.json());
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// Remove background
app.post('/api/remove-background', requirePassword, upload.single('image'), async (req, res) => {
    try {
        if (!FAL_API_KEY) return res.status(500).json({ error: 'API key not configured' });
        if (!req.file) return res.status(400).json({ error: 'No image provided' });

        console.log('🎨 Background removal requested:', req.file.originalname);
        const base64Image = req.file.buffer.toString('base64');
        const imageUrl = `data:${req.file.mimetype};base64,${base64Image}`;

        const submitRes = await fetch('https://queue.fal.run/fal-ai/birefnet/v2', {
            method: 'POST',
            headers: { 'Authorization': `Key ${FAL_API_KEY}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ image_url: imageUrl }),
        });

        if (!submitRes.ok) {
            const errText = await submitRes.text();
            return res.status(submitRes.status).json({ error: `Background removal submit failed: ${submitRes.statusText}`, details: errText });
        }

        const submitData = await submitRes.json();
        console.log('✅ Background removal job submitted! ID:', submitData.request_id);
        res.json({ success: true, requestId: submitData.request_id, message: 'Background removal job submitted' });

    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// Check background removal status
app.get('/api/bg-status/:requestId', requirePassword, async (req, res) => {
    try {
        if (!FAL_API_KEY) return res.status(500).json({ error: 'API key not configured' });
        const { requestId } = req.params;
        const statusRes = await fetch(`https://queue.fal.run/fal-ai/birefnet/requests/${requestId}/status`, {
            headers: { 'Authorization': `Key ${FAL_API_KEY}` }
        });
        if (!statusRes.ok) return res.status(statusRes.status).json({ error: `Status check failed: ${statusRes.statusText}` });
        res.json(await statusRes.json());
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

