// Serve frontend — HTML embedded directly, no public/ folder needed
const HTML_B64 = '';
const HTML_CONTENT = Buffer.from(HTML_B64, 'base64').toString('utf-8');

app.get('/', (req, res) => {
    res.setHeader('Content-Type', 'text/html');
    res.send(HTML_CONTENT);
});

app.listen(PORT, () => {
    console.log('🚀 My3DConverter server running on port', PORT);
    console.log('🔑 API Key status:', FAL_API_KEY ? '✅ Configured' : '❌ Missing');
    console.log('📍 Visit: http://localhost:' + PORT);
});
